// CRMServiceServer is the server API for CRMService service.
// All implementations must embed UnimplementedCRMServiceServer
// for forward compatibility.
type CRMServiceServer interface {
	CreatePipeline(context.Context, *CreatePipelineRequest) (*CreatePipelineResponse, error)
	GetPipeline(context.Context, *GetPipelineRequest) (*GetPipelineResponse, error)
	ListPipelines(context.Context, *ListPipelinesRequest) (*ListPipelinesResponse, error)
	UpdatePipeline(context.Context, *UpdatePipelineRequest) (*UpdatePipelineResponse, error)
	ArchivePipeline(context.Context, *ArchivePipelineRequest) (*ArchivePipelineResponse, error)
	CreateStage(context.Context, *CreateStageRequest) (*CreateStageResponse, error)
	UpdateStage(context.Context, *UpdateStageRequest) (*UpdateStageResponse, error)
	DeleteStage(context.Context, *DeleteStageRequest) (*DeleteStageResponse, error)
	ReorderStages(context.Context, *ReorderStagesRequest) (*ReorderStagesResponse, error)
	// Contact RPCs (Phase 3 -- integration with cg-users)
	CreateContact(context.Context, *CreateContactRequest) (*CreateContactResponse, error)
	GetContact(context.Context, *GetContactRequest) (*GetContactResponse, error)
	ListContacts(context.Context, *ListContactsRequest) (*ListContactsResponse, error)
	SearchContacts(context.Context, *SearchContactsRequest) (*SearchContactsResponse, error)
	UpdateContact(context.Context, *UpdateContactRequest) (*UpdateContactResponse, error)
	DeleteContact(context.Context, *DeleteContactRequest) (*DeleteContactResponse, error)
	// Vehicle RPCs (Phase 3 -- integration with cg-users garage)
	AddVehicle(context.Context, *AddVehicleRequest) (*AddVehicleResponse, error)
	GetVehicle(context.Context, *GetVehicleRequest) (*GetVehicleResponse, error)
	ListVehiclesByContact(context.Context, *ListVehiclesByContactRequest) (*ListVehiclesByContactResponse, error)
	GetServiceHistory(context.Context, *GetServiceHistoryRequest) (*GetServiceHistoryResponse, error)
	GetGarageByPhone(context.Context, *GetGarageByPhoneRequest) (*GetGarageByPhoneResponse, error)
	LookupVehicle(context.Context, *LookupVehicleRequest) (*LookupVehicleResponse, error)
	// Deal RPCs (Phase 4 -- deal lifecycle)
	CreateDeal(context.Context, *CreateDealRequest) (*CreateDealResponse, error)
	GetDeal(context.Context, *GetDealRequest) (*GetDealResponse, error)
	ListDeals(context.Context, *ListDealsRequest) (*ListDealsResponse, error)
	UpdateDeal(context.Context, *UpdateDealRequest) (*UpdateDealResponse, error)
	MoveDealStage(context.Context, *MoveDealStageRequest) (*MoveDealStageResponse, error)
	CloseDeal(context.Context, *CloseDealRequest) (*CloseDealResponse, error)
	ReOpenDeal(context.Context, *ReOpenDealRequest) (*ReOpenDealResponse, error)
	GetDealActivities(context.Context, *GetDealActivitiesRequest) (*GetDealActivitiesResponse, error)
	GetContactActivities(context.Context, *GetContactActivitiesRequest) (*GetContactActivitiesResponse, error)
	// Lead RPCs (Phase 5 -- lead capture and conversion)
	CreateLead(context.Context, *CreateLeadRequest) (*CreateLeadResponse, error)
	GetLead(context.Context, *GetLeadRequest) (*GetLeadResponse, error)
	ListLeads(context.Context, *ListLeadsRequest) (*ListLeadsResponse, error)
	ChangeLeadStatus(context.Context, *ChangeLeadStatusRequest) (*ChangeLeadStatusResponse, error)
	ConvertLead(context.Context, *ConvertLeadRequest) (*ConvertLeadResponse, error)
	// Task RPCs (Phase 6 -- task management with RBAC)
	CreateTask(context.Context, *CreateTaskRequest) (*CreateTaskResponse, error)
	GetTask(context.Context, *GetTaskRequest) (*GetTaskResponse, error)
	ListTasks(context.Context, *ListTasksRequest) (*ListTasksResponse, error)
	UpdateTaskStatus(context.Context, *UpdateTaskStatusRequest) (*UpdateTaskStatusResponse, error)
	UpdateTask(context.Context, *UpdateTaskRequest) (*UpdateTaskResponse, error)
	// Custom Field RPCs (Phase 7 -- custom field definitions per org/entity)
	CreateCustomFieldDefinition(context.Context, *CreateCustomFieldDefinitionRequest) (*CreateCustomFieldDefinitionResponse, error)
	GetCustomFieldDefinition(context.Context, *GetCustomFieldDefinitionRequest) (*GetCustomFieldDefinitionResponse, error)
	ListCustomFieldDefinitions(context.Context, *ListCustomFieldDefinitionsRequest) (*ListCustomFieldDefinitionsResponse, error)
	UpdateCustomFieldDefinition(context.Context, *UpdateCustomFieldDefinitionRequest) (*UpdateCustomFieldDefinitionResponse, error)
	DeleteCustomFieldDefinition(context.Context, *DeleteCustomFieldDefinitionRequest) (*DeleteCustomFieldDefinitionResponse, error)
	// Webhook Subscription RPCs (Phase 7 -- webhook delivery)
	CreateWebhookSubscription(context.Context, *CreateWebhookSubscriptionRequest) (*CreateWebhookSubscriptionResponse, error)
	ListWebhookSubscriptions(context.Context, *ListWebhookSubscriptionsRequest) (*ListWebhookSubscriptionsResponse, error)
	UpdateWebhookSubscription(context.Context, *UpdateWebhookSubscriptionRequest) (*UpdateWebhookSubscriptionResponse, error)
	DeleteWebhookSubscription(context.Context, *DeleteWebhookSubscriptionRequest) (*DeleteWebhookSubscriptionResponse, error)
	// Analytics RPCs (Phase 8)
	GetFunnelConversion(context.Context, *GetFunnelConversionRequest) (*GetFunnelConversionResponse, error)
	GetManagerStats(context.Context, *GetManagerStatsRequest) (*GetManagerStatsResponse, error)
	GetDealVolume(context.Context, *GetDealVolumeRequest) (*GetDealVolumeResponse, error)
	mustEmbedUnimplementedCRMServiceServer()
}

